B.Ll=new A.bh(B.bX,[B.IA,B.Ju,B.Hf,'\ud83e\uddfe To pay your bills:\n\n1\ufe0f\u20e3 On the Home screen tap "Bill Payment"\n2\ufe0f\u20e3 Choose the bill category:\n   \u26a1 Electricity\n   \ud83d\udca7 Water\n   \ud83d\udcf6 Internet\n   \ud83c\udfdb\ufe0f Administration\n   \ud83d\udcfa TV / TOD by BeIN\n   \ud83d\udee1\ufe0f Insurance\n   \ud83d\udcbc Finance\n   \ud83c\udf93 Education\n   \u2708\ufe0f Air Transport\n3\ufe0f\u20e3 Choose the company\n4\ufe0f\u20e3 Enter your customer ID\n5\ufe0f\u20e3 Your bill details will appear\n6\ufe0f\u20e3 Enter your secret PIN to pay\n\n\u2705 Payment confirmed instantly!','\ud83e\uddfe \u0644\u062a\u0633\u062f\u064a\u062f \u0627\u0644\u0641\u0648\u0627\u062a\u064a\u0631:\n\n1\ufe0f\u20e3 \u0641\u064a \u0627\u0644\u0635\u0641\u062d\u0629 \u0627\u0644\u0631\u0626\u064a\u0633\u064a\u0629 \u0627\u0636\u063a\u0637 \u0639\u0644\u0649 "\u062a\u0633\u062f\u064a\u062f \u0627\u0644\u0641\u0648\u0627\u062a\u064a\u0631"\n2\ufe0f\u20e3 \u0627\u062e\u062a\u0631 \u0646\u0648\u0639 \u0627\u0644\u0641\u0627\u062a\u0648\u0631\u0629:\n   \u26a1 \u0643\u0647\u0631\u0628\u0627\u0621\n   \ud83d\udca7 \u0645\u0627\u0621\n   \ud83d\udcf6 \u0625\u0646\u062a\u0631\u0646\u062a\n   \ud83c\udfdb\ufe0f \u0625\u062f\u0627\u0631\u0629\n   \ud83d\udcfa \u062a\u0644\u0641\u0632\u064a\u0648\u0646 / TOD by BeIN\n   \ud83d\udee1\ufe0f \u062a\u0623\u0645\u064a\u0646\n   \ud83d\udcbc \u0645\u0627\u0644\u064a\u0629\n   \ud83c\udf93 \u062a\u0639\u0644\u064a\u0645\n   \u2708\ufe0f \u0646\u0642\u0644 \u062c\u0648\u064a\n3\ufe0f\u20e3 \u0627\u062e\u062a\u0631 \u0627\u0644\u0634\u0631\u0643\u0629\n4\ufe0f\u20e3 \u0623\u062f\u062e\u0644 \u0645\u0639\u0631\u0651\u0641\u0643 (ID)\n5\ufe0f\u20e3 \u0633\u062a\u0638\u0647\u0631 \u062a\u0641\u0627\u0635\u064a\u0644 \u0641\u0627\u062a\u0648\u0631\u062a\u0643\n6\ufe0f\u20e3 \u0623\u062f\u062e\u0644 \u0631\u0642\u0645\u0643 \u0627\u0644\u0633\u0631\u064a \u0644\u0644\u062f\u0641\u0639\n\n\u2705 \u064a\u062a\u0645 \u062a\u0623\u0643\u064a\u062f \u0627\u0644\u062f\u0641\u0639 \u0641\u0648\u0631\u0627\u064b!',"\ud83e\uddfe Pour payer vos factures:\n\n1\ufe0f\u20e3 Sur l'accueil appuyez \"Paiement de factures\"\n2\ufe0f\u20e3 Choisissez la cat\xe9gorie:\n   \u26a1 \xc9lectricit\xe9\n   \ud83d\udca7 Eau\n   \ud83d\udcf6 Internet\n   \ud83c\udfdb\ufe0f Administration\n   \ud83d\udcfa TV / TOD by BeIN\n   \ud83d\udee1\ufe0f Assurance\n   \ud83d\udcbc Finance\n   \ud83c\udf93 \xc9ducation\n   \u2708\ufe0f Transport a\xe9rien\n3\ufe0f\u20e3 Choisissez la soci\xe9t\xe9\n4\ufe0f\u20e3 Entrez votre identifiant client (ID)\n5\ufe0f\u20e3 Les d\xe9tails de votre facture s'affichent\n6\ufe0f\u20e3 Entrez votre code PIN pour payer\n\n\u2705 Paiement confirm\xe9 instantan\xe9ment!"],t.EU)
