B.Lq=new A.bh(B.bX,[B.I8,B.Jf,B.Je,'\ud83c\udfea To pay a merchant (B-Pay):\n\n1\ufe0f\u20e3 On the Home screen tap "B-Pay"\n2\ufe0f\u20e3 Enter the merchant ID\n3\ufe0f\u20e3 Enter the amount to pay\n4\ufe0f\u20e3 Enter your secret PIN to confirm\n\n\u2705 Payment sent to the merchant instantly!','\ud83c\udfea \u0644\u0644\u062f\u0641\u0639 \u0639\u0646\u062f \u0627\u0644\u062a\u062c\u0627\u0631 (B-Pay):\n\n1\ufe0f\u20e3 \u0641\u064a \u0627\u0644\u0635\u0641\u062d\u0629 \u0627\u0644\u0631\u0626\u064a\u0633\u064a\u0629 \u0627\u0636\u063a\u0637 \u0639\u0644\u0649 "B-Pay"\n2\ufe0f\u20e3 \u0623\u062f\u062e\u0644 \u0645\u0639\u0631\u0651\u0641 \u0627\u0644\u062a\u0627\u062c\u0631\n3\ufe0f\u20e3 \u0623\u062f\u062e\u0644 \u0627\u0644\u0645\u0628\u0644\u063a \u0627\u0644\u0645\u0631\u0627\u062f \u062f\u0641\u0639\u0647\n4\ufe0f\u20e3 \u0623\u062f\u062e\u0644 \u0631\u0642\u0645\u0643 \u0627\u0644\u0633\u0631\u064a \u0644\u0644\u062a\u0623\u0643\u064a\u062f\n\n\u2705 \u064a\u062a\u0645 \u0625\u0631\u0633\u0627\u0644 \u0627\u0644\u062f\u0641\u0639 \u0644\u0644\u062a\u0627\u062c\u0631 \u0641\u0648\u0631\u0627\u064b!',"\ud83c\udfea Pour payer un marchand (B-Pay):\n\n1\ufe0f\u20e3 Sur l'accueil appuyez \"B-Pay\"\n2\ufe0f\u20e3 Entrez l'identifiant du marchand\n3\ufe0f\u20e3 Entrez le montant \xe0 payer\n4\ufe0f\u20e3 Entrez votre code PIN pour confirmer\n\n\u2705 Paiement envoy\xe9 au marchand instantan\xe9ment!"],t.EU)
